dat=['<b>${nodeTxt}</b>', '<i>${nodeTxt}</i>', '<u>${nodeTxt}</u>', '<div id="${c_action.id}" class="action hl"></div>', '<span class="is-sr-only">${loc(\'not_active\')}</span>', '<a class="button is-dark${clss}" role="link"><span class="aTitle" v-html="$options.filters.title(title)"></span></a><a role="button" v-on:click="describe" class="is-sr-only">{{ title }} description</a>', '<div class="tabWon_stats" id="tabWonStats"></div>', '<span class="has-text-success">Congratulations! You have won the game! </span><div class="has-text-success tabWonGoal">You managed to <b>${stringPack[global.opts.goal]}</b>!</div>', '<div id="wonPanel" class="vb"></div>', '<div class="has-text-success wonPanelTitle">${stringPack[i]}</div>', '<div>\n                <span class="has-text-warning wonPanelSub">${stringPack[cs]}:</span> {{${inp}}}\n                </div>', '<div>\n    //         <span class="has-text-warning">${stringPack[i]}:</span> {{${inp}}}\n    //         </div>']